import React, { useState } from 'react';
import { analyzeSymptoms, logout } from '../services/api';

function SymptomAnalyzer({ onLogout }) {
    const [symptoms, setSymptoms] = useState('');
    const [temperature, setTemperature] = useState('');
    const [duration, setDuration] = useState('');
    const [loading, setLoading] = useState(false);
    const [result, setResult] = useState(null);
    const [error, setError] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');
        setResult(null);

        const res = await analyzeSymptoms({
            symptoms_text: symptoms,
            temperature: parseFloat(temperature) || 0,
            duration_days: parseInt(duration) || 1,
        });

        if (res.success) {
            setResult(res.data);
        } else {
            setError(res.error);
        }
        setLoading(false);
    };

    const getTriageStyle = (level) => {
        switch(level) {
            case 'emergency': return { backgroundColor: '#dc3545', color: 'white' };
            case 'urgent': return { backgroundColor: '#fd7e14', color: 'white' };
            default: return { backgroundColor: '#28a745', color: 'white' };
        }
    };

    return (
        <div>
            <div style={styles.header}>
                <h2>🏥 Community Health Tracker</h2>
                <button onClick={onLogout} style={styles.logoutBtn}>Logout</button>
            </div>

            <div style={styles.container}>
                <div style={styles.card}>
                    <h3>🩺 Symptom Checker</h3>

                    <form onSubmit={handleSubmit}>
                        <div style={styles.inputGroup}>
                            <label>Describe your symptoms</label>
                            <textarea
                                value={symptoms}
                                onChange={(e) => setSymptoms(e.target.value)}
                                placeholder="Example: I have a fever and headache for 2 days..."
                                rows={4}
                                required
                                style={styles.textarea}
                            />
                        </div>

                        <div style={styles.row}>
                            <div style={styles.inputGroup}>
                                <label>Temperature (°C)</label>
                                <input
                                    type="number"
                                    step="0.1"
                                    value={temperature}
                                    onChange={(e) => setTemperature(e.target.value)}
                                    placeholder="38.5"
                                    style={styles.input}
                                />
                            </div>

                            <div style={styles.inputGroup}>
                                <label>Duration (days)</label>
                                <input
                                    type="number"
                                    value={duration}
                                    onChange={(e) => setDuration(e.target.value)}
                                    placeholder="2"
                                    style={styles.input}
                                />
                            </div>
                        </div>

                        <button type="submit" disabled={loading} style={styles.analyzeBtn}>
                            {loading ? 'Analyzing...' : '🔍 Analyze Symptoms'}
                        </button>
                    </form>

                    {error && <div style={styles.error}>{error}</div>}

                    {result && (
                        <div style={styles.resultContainer}>
                            <h4>📊 Analysis Result</h4>
                            <div style={styles.resultCard}>
                                <div style={styles.resultRow}>
                                    <strong>Triage Level:</strong>
                                    <span style={{ ...styles.badge, ...getTriageStyle(result.triage_level) }}>
                                        {result.triage_display || result.triage_level.toUpperCase()}
                                    </span>
                                </div>

                                <div style={styles.resultRow}>
                                    <strong>Confidence:</strong>
                                    <span>{(result.confidence_score * 100).toFixed(0)}%</span>
                                </div>

                                <div style={styles.resultRow}>
                                    <strong>Possible Condition:</strong>
                                    <span>{result.possible_condition}</span>
                                </div>

                                <div style={styles.resultRow}>
                                    <strong>Recommendation:</strong>
                                    <span>{result.recommendation}</span>
                                </div>

                                {/* Medications Section */}
                                {result.medications && result.medications.length > 0 && (
                                    <>
                                        <div style={styles.divider}></div>
                                        <div style={styles.medicationsHeader}>
                                            <strong>💊 Recommended Medications:</strong>
                                        </div>
                                        {result.medications.map((med, index) => (
                                            <div key={index} style={styles.medicationCard}>
                                                <div style={styles.medicationName}>
                                                    <strong>{med.name}</strong>
                                                </div>
                                                <div style={styles.medicationDetail}>
                                                    <span style={styles.medicationLabel}>Dosage:</span> {med.dosage}
                                                </div>
                                                <div style={styles.medicationDetail}>
                                                    <span style={styles.medicationLabel}>Note:</span> {med.note}
                                                </div>
                                            </div>
                                        ))}
                                        <div style={styles.disclaimer}>
                                            ⚠️ This is for informational purposes only. Consult a healthcare professional before taking any medication.
                                        </div>
                                    </>
                                )}
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

const styles = {
    header: {
        backgroundColor: '#007bff',
        color: 'white',
        padding: '1rem 2rem',
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
    },
    logoutBtn: {
        backgroundColor: '#dc3545',
        color: 'white',
        border: 'none',
        padding: '0.5rem 1rem',
        borderRadius: '6px',
        cursor: 'pointer',
        fontSize: '1rem',
    },
    container: {
        maxWidth: '800px',
        margin: '2rem auto',
        padding: '0 1rem',
    },
    card: {
        backgroundColor: 'white',
        padding: '2rem',
        borderRadius: '12px',
        boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
    },
    inputGroup: {
        marginBottom: '1rem',
    },
    input: {
        width: '100%',
        padding: '0.75rem',
        border: '1px solid #ddd',
        borderRadius: '6px',
        fontSize: '1rem',
        marginTop: '0.25rem',
        boxSizing: 'border-box',
    },
    textarea: {
        width: '100%',
        padding: '0.75rem',
        border: '1px solid #ddd',
        borderRadius: '6px',
        fontSize: '1rem',
        marginTop: '0.25rem',
        fontFamily: 'inherit',
        boxSizing: 'border-box',
    },
    row: {
        display: 'grid',
        gridTemplateColumns: '1fr 1fr',
        gap: '1rem',
    },
    analyzeBtn: {
        width: '100%',
        padding: '0.75rem',
        backgroundColor: '#28a745',
        color: 'white',
        border: 'none',
        borderRadius: '6px',
        fontSize: '1rem',
        fontWeight: '500',
        cursor: 'pointer',
        marginTop: '0.5rem',
    },
    error: {
        backgroundColor: '#f8d7da',
        color: '#721c24',
        padding: '0.75rem',
        borderRadius: '6px',
        marginTop: '1rem',
    },
    resultContainer: {
        marginTop: '2rem',
        paddingTop: '1rem',
        borderTop: '2px solid #eee',
    },
    resultCard: {
        backgroundColor: '#f8f9fa',
        padding: '1rem',
        borderRadius: '8px',
        marginTop: '1rem',
    },
    resultRow: {
        display: 'flex',
        justifyContent: 'space-between',
        padding: '0.75rem 0',
        borderBottom: '1px solid #eee',
    },
    badge: {
        padding: '0.25rem 0.75rem',
        borderRadius: '20px',
        fontSize: '0.875rem',
        fontWeight: 'bold',
    },
    divider: {
        borderTop: '1px solid #ddd',
        margin: '1rem 0',
    },
    medicationsHeader: {
        marginBottom: '0.75rem',
        fontSize: '1rem',
        color: '#333',
    },
    medicationCard: {
        backgroundColor: '#fff',
        padding: '0.75rem',
        borderRadius: '6px',
        marginBottom: '0.75rem',
        borderLeft: '4px solid #28a745',
        boxShadow: '0 1px 2px rgba(0,0,0,0.05)',
    },
    medicationName: {
        fontSize: '1rem',
